// /frontend/src/components/BottomBar.jsx
import React from "react";
export default function BottomBar() {
  return (
    <nav className="fixed bottom-0 left-0 right-0 z-40">
      <div className="mx-auto max-w-3xl px-4 pb-5">
        <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 px-4 py-3 flex justify-around">
          <button className="opacity-90">🏠</button>
          <button className="opacity-75">🗺️</button>
          <button className="opacity-75">💬</button>
          <button className="opacity-75">⚙️</button>
        </div>
      </div>
    </nav>
  );
}
